-- Inserta los 21 perfumes reales de FRAGANTI en Supabase.
-- Corre esto DESPUÉS de crear la tabla (schema.sql), en el SQL Editor de Supabase.


-- Reinicia el contador de ids para que el próximo perfume que agregues
-- desde el panel no choque con estos 21.
select setval(pg_get_serial_sequence('public.perfumes', 'id'), (select max(id) from public.perfumes));